import { apiKeyLocalization } from "@better-auth-ui/core/plugins"
import {
  type ApiKeyAuthClient,
  listApiKeysOptions,
  useAuth,
  useSession
} from "@better-auth-ui/solid"
import { createQuery } from "@tanstack/solid-query"
import { createSignal, For, Show } from "solid-js"
import { ApiKey } from "@/components/auth/api-key/api-key"
import { ApiKeySkeleton } from "@/components/auth/api-key/api-key-skeleton"
import { ApiKeysEmpty } from "@/components/auth/api-key/api-keys-empty"
import { CreateApiKeyDialog } from "@/components/auth/api-key/create-api-key-dialog"
import { shouldLoadDeviceSessions } from "@/components/auth/settings/shared/helpers"
import type { ListedApiKey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"
import { ItemSeparator } from "@/components/ui/item"

export function ApiKeysSettings() {
  const auth = useAuth()
  const session = useSession(auth.authClient)
  const userId = () => session.data?.user.id
  const [isCreateDialogOpen, setIsCreateDialogOpen] = createSignal(false)
  const apiKeys = createQuery(() => ({
    ...listApiKeysOptions(auth.authClient as ApiKeyAuthClient, userId()),
    enabled: shouldLoadDeviceSessions({
      isSsr: import.meta.env.SSR,
      userId: userId()
    })
  }))
  const keys = () => apiKeys.data?.apiKeys ?? []

  return (
    <div class="flex flex-col gap-3">
      <div class="flex items-end justify-between gap-3">
        <h2 class="truncate text-sm font-semibold">
          {apiKeyLocalization.apiKeys}
        </h2>
        <Dialog
          open={isCreateDialogOpen()}
          onOpenChange={setIsCreateDialogOpen}
        >
          <DialogTrigger
            as={Button}
            class="shrink-0"
            disabled={apiKeys.isPending}
            size="sm"
          >
            {apiKeyLocalization.createApiKey}
          </DialogTrigger>
          <CreateApiKeyDialog onOpenChange={setIsCreateDialogOpen} />
        </Dialog>
      </div>

      <Card class="p-0">
        <CardContent class="p-0">
          <Show when={!apiKeys.isPending} fallback={<ApiKeySkeleton />}>
            <Show
              when={keys().length > 0}
              fallback={
                <ApiKeysEmpty
                  onCreatePress={() => setIsCreateDialogOpen(true)}
                />
              }
            >
              <For each={keys()}>
                {(apiKey, index) => (
                  <>
                    <Show when={index() > 0}>
                      <ItemSeparator />
                    </Show>
                    <ApiKey apiKey={apiKey as ListedApiKey} />
                  </>
                )}
              </For>
            </Show>
          </Show>
        </CardContent>
      </Card>
    </div>
  )
}

import { apiKeyLocalization } from "@better-auth-ui/core/plugins"
import { useAuth } from "@better-auth-ui/solid"
import { Key, X } from "lucide-solid"
import { createSignal } from "solid-js"
import { DeleteApiKeyDialog } from "@/components/auth/api-key/delete-api-key-dialog"
import type { ListedApiKey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"

export function ApiKey(props: { apiKey: ListedApiKey }) {
  const auth = useAuth()
  const [deleteOpen, setDeleteOpen] = createSignal(false)
  const preview = () => `${props.apiKey.start}${"*".repeat(16)}`

  return (
    <div class="flex items-center gap-3 p-0">
      <div class="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
        <Key class="size-4.5" />
      </div>

      <div class="flex min-w-0 flex-col">
        <span class="truncate font-medium text-sm leading-tight">
          {props.apiKey.name || apiKeyLocalization.apiKey}
        </span>
        <span class="truncate font-mono text-muted-foreground text-xs">
          {preview()}
        </span>
        <span class="text-muted-foreground text-xs">
          {new Date(props.apiKey.createdAt).toLocaleString(undefined, {
            dateStyle: "medium",
            timeStyle: "short"
          })}
        </span>
      </div>

      <Dialog open={deleteOpen()} onOpenChange={setDeleteOpen}>
        <DialogTrigger
          as={Button}
          aria-label={apiKeyLocalization.deleteApiKey}
          class="ml-auto shrink-0"
          size="sm"
          variant="outline"
        >
          <X />
          {auth.localization.settings.delete}
        </DialogTrigger>
        <DeleteApiKeyDialog
          apiKey={props.apiKey}
          onOpenChange={setDeleteOpen}
        />
      </Dialog>
    </div>
  )
}

